use rand::Rng;
use rand::distributions::Alphanumeric;
use ring::rand::SystemRandom;

pub fn generate_api_token() -> String {
    let random = SystemRandom::new();
    let token: String = random
        .sample_iter(Alphanumeric)
        .take(40)
        .collect();
    token
}